// Gera lista de datas dos últimos 7 dias para sync incremental
const items = $input.all();
const lojas = Array.isArray(items[0].json) ? items[0].json : [];

const hoje = new Date();
const datas = [];
for (let i = 1; i <= 7; i++) {
  const d = new Date(hoje);
  d.setDate(d.getDate() - i);
  datas.push(d.toISOString().slice(0, 10));
}

const out = [];
for (const loja of lojas) {
  if (!loja.accessToken) continue;
  for (const date of datas) {
    out.push({
      json: { ...loja, date }
    });
  }
}
return out;

// Mapeia os 4 responses para o payload do /api/ingest/meta-ads
const metricasRaw   = $('Meta API — Métricas diárias').first().json;
const demosRaw      = $('Meta API — Demographics').first().json;
const geoRaw        = $('Meta API — Geo').first().json;
const adsRaw        = $('Meta API — Top Ads').first().json;
const ctx           = $('Expandir lojas × datas').first().json;

function sumActions(actions, type) {
  if (!Array.isArray(actions)) return 0;
  const found = actions.find(a => a.action_type === type);
  return found ? parseInt(found.value, 10) : 0;
}

const metricsData   = metricasRaw?.data?.[0];
const metrics = metricsData ? {
  spend:       parseFloat(metricsData.spend || '0'),
  impressions: parseInt(metricsData.impressions || '0', 10),
  clicks:      parseInt(metricsData.clicks || '0', 10),
  leads:       sumActions(metricsData.actions, 'lead') +
               sumActions(metricsData.actions, 'onsite_conversion.messaging_conversation_started_7d'),
  messages:    sumActions(metricsData.actions, 'onsite_conversion.messaging_conversation_started_7d'),
} : undefined;

const demographics = (demosRaw?.data || []).map(d => ({
  dimension:   d.age ? 'age' : d.gender ? 'gender' : 'other',
  bucket:      d.age || d.gender || 'unknown',
  spend:       parseFloat(d.spend || '0'),
  clicks:      parseInt(d.clicks || '0', 10),
  impressions: parseInt(d.impressions || '0', 10),
  leads:       sumActions(d.actions, 'lead'),
}));

const geo = (geoRaw?.data || []).map(g => ({
  state:  (g.region || '').slice(0, 2).toUpperCase(),
  spend:  parseFloat(g.spend || '0'),
  clicks: parseInt(g.clicks || '0', 10),
  leads:  sumActions(g.actions, 'lead'),
})).filter(g => g.state.length === 2);

const creatives = (adsRaw?.data || []).map(ad => {
  const ins = ad.insights?.data?.[0];
  if (!ins) return null;
  return {
    external_id:  ad.id,
    name:         ad.name,
    type:         'image',
    spend:        parseFloat(ins.spend || '0'),
    ctr:          parseFloat(ins.ctr || '0'),
    leads:        sumActions(ins.actions, 'lead'),
    messages:     sumActions(ins.actions, 'onsite_conversion.messaging_conversation_started_7d'),
    period_start: ctx.date,
    period_end:   ctx.date,
  };
}).filter(Boolean);

return [{
  json: {
    tenant_slug:       ctx.tenantSlug,
    store_external_id: ctx.storeExternalId,
    date:              ctx.date,
    accessToken:       ctx.accessToken,
    metrics,
    demographics,
    geo,
    creatives,
  }
}];
